package market.service.impl;

import market.dao.DistilleryDAO;
import market.domain.Distillery;
import market.domain.Region;
import market.service.DistilleryService;
import market.service.RegionService;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Comparator;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@Service
public class DistilleryServiceImpl implements DistilleryService {
	private final RegionService regionService;
	private final DistilleryDAO distilleryDAO;

	public DistilleryServiceImpl(RegionService regionService, DistilleryDAO distilleryDAO) {
		this.regionService = regionService;
		this.distilleryDAO = distilleryDAO;
	}

	@Transactional(readOnly = true)
	@Override
	public List<Distillery> findAll() {
		return distilleryDAO.findAll().stream()
			.sorted(Comparator.comparing(Distillery::getTitle))
			.collect(Collectors.toList());
	}

	@Transactional(readOnly = true)
	@Override
	public List<Distillery> findByRegion(Region region) {
		return distilleryDAO.findByRegionOrderByTitleAsc(region);
	}

	@Transactional(readOnly = true)
	@Override
	public Distillery findById(long distilleryId) {
		return distilleryDAO.findById(distilleryId).orElse(null);
	}

	@Transactional(readOnly = true)
	@Override
	public Distillery findByTitle(String title) {
		return distilleryDAO.findByTitle(title);
	}

	@Transactional
	@Override
	public void create(Distillery newDistillery, String regionName) {
		saveInternal(newDistillery, regionName);
	}

	@Override
	public void update(long distilleryId, Distillery changedDistillery, String regionName) {
		Optional<Distillery> originalDistillery = distilleryDAO.findById(distilleryId);
		if (originalDistillery.isPresent()) {
			changedDistillery.setId(originalDistillery.get().getId());
			saveInternal(changedDistillery, regionName);
		}
	}

	private void saveInternal(Distillery distillery, String regionName) {
		Region region = regionService.findByName(regionName);
		if (region != null) {
			distillery.setRegion(region);
			distilleryDAO.save(distillery);
		}
	}

	@Transactional
	@Override
	public void delete(long distilleryId) {
		distilleryDAO.deleteById(distilleryId);
	}
}

package br.com.fatecmogidascruzes.domain;

import java.io.Serializable;
import java.time.LocalDateTime;
import java.util.Objects;
import java.util.UUID;

import javax.persistence.Access;
import javax.persistence.AccessType;
import javax.persistence.Basic;
import javax.persistence.Column;
import javax.persistence.GeneratedValue;
import javax.persistence.GenerationType;
import javax.persistence.Id;
import javax.persistence.MappedSuperclass;
import javax.validation.constraints.NotNull;

import com.devskiller.friendly_id.FriendlyId;

import lombok.AllArgsConstructor;
import lombok.Getter;
import lombok.Setter;

@Access(AccessType.FIELD)
@AllArgsConstructor
@Getter
@MappedSuperclass
@Setter
public abstract class EntityImpl implements Entity, Serializable {

	private static final long serialVersionUID = 1L;

	protected Long id;

	@Column(name = "creation_date", nullable = false, updatable = false)
	protected LocalDateTime creationDate;

	@Column(name = "last_update", nullable = false)
	protected LocalDateTime lastUpdate;

	@Basic
	@Column(name = "enabled", nullable = false)
	protected boolean enabled = true;

	@Basic
	@Column(name = "hash", nullable = false, updatable = false)
	protected UUID hash;

	@Access(AccessType.PROPERTY)
	@Column(name = "id", nullable = false, unique = true)
	@GeneratedValue(strategy = GenerationType.AUTO)
	@Id
	@NotNull
	public Long getId() {
		return this.id;
	}

	public EntityImpl() {
		this.creationDate = LocalDateTime.now();
		this.lastUpdate = LocalDateTime.now();
		this.hash = UUID.randomUUID();
		this.enabled = true;
	}

	public boolean getEnabled() {
		return this.isEnabled();
	}

	public boolean isEnabled() {
		return this.enabled;
	}

	public String getHashString() {
		return FriendlyId.toFriendlyId(hash);
	}

	@Override
	public int hashCode() {
		int hash = id != null ? id.hashCode() : 0;
		return hash;
	}

	@Override
	public boolean equals(Object other) {
		if (null == other) {
			return false;
		}
		if (!getClass().getName().equals(other.getClass().getName())) {
			return false;
		}
		Entity otherEntity = (Entity) other;
		if (null == getId() || null == otherEntity.getId()) {
			return this == otherEntity;
		}
		if (0 == getId() && 0 == otherEntity.getId()) {
			return false;
		}
		return Objects.equals(getId(), otherEntity.getId());
	}

}

package br.com.fatecmogidascruzes.storage;

import static java.nio.file.FileSystems.getDefault;

import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;

import javax.annotation.PostConstruct;
import javax.imageio.ImageIO;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;
import org.springframework.web.multipart.MultipartFile;

@Profile("local-storage")
@Component
public class LocalStorage implements Storage {

	@Value("${storage.path}")
	private String storagePath;

	private Path path;

	// The @Value is available only after constructions.
	@PostConstruct
	public void init() {
		// this.path = getDefault().getPath(storagePath, "files");
		this.path = getDefault().getPath(storagePath, "");

		try {
			Files.createDirectories(path);
		} catch (IOException error) {
			throw new RuntimeException("Error creating files' folder.", error);
		}
		try {
			Files.createDirectories(getDefault().getPath(storagePath, "tmp"));
		} catch (IOException error) {
			throw new RuntimeException("Error creating temporary files' folder.", error);
		}
	}

	@Override
	public String store(MultipartFile file) {
		store(file, file.getName());
		return file.getName();
	}

	@Override
	public Path getPath() {
		return this.path;
	}

	@Override
	public void store(MultipartFile arquivo, String name) {
		try {
			arquivo.transferTo(new File(this.path.toAbsolutePath().toString() + getDefault().getSeparator() + name));
		} catch (IOException error) {
			throw new RuntimeException("Error saving local file.", error);
		}
	}

	@Override
	public byte[] loadBytes(String name) {
		try {
			return Files.readAllBytes(this.path.resolve(name));
		} catch (IOException error) {
			error.printStackTrace();
			throw new RuntimeException("Error loading local file.", error);
		}
	}

	@Override
	public File loadFile(String name) {
		return this.path.resolve(name).toFile();
	}

	@Override
	public Path getPathTo(String fileName) {
		return this.path.resolve(fileName);
	}

	@Override
	public BufferedImage loadImage(String name) throws IOException {
		return ImageIO.read(this.path.resolve(name).toFile());
	}

	@Override
	public void remove(String name) {
		try {
			Files.delete(this.path.resolve(name));
		} catch (IOException error) {
			throw new RuntimeException("Error removing local file.", error);
		}
	}

}

package org.lognet.springboot.grpc.autoconfigure.consul;

import org.lognet.springboot.grpc.context.GRpcServerInitializedEvent;
import org.springframework.cloud.consul.serviceregistry.ConsulRegistration;
import org.springframework.cloud.consul.serviceregistry.ConsulServiceRegistry;
import org.springframework.context.ApplicationContext;
import org.springframework.context.SmartLifecycle;
import org.springframework.context.event.EventListener;

import java.util.List;
import java.util.stream.Collectors;

public class GrpcConsulRegistrar implements SmartLifecycle {

    private final ConsulServiceRegistry consulServiceRegistry;

    private List<ConsulRegistration> registrations;

    public GrpcConsulRegistrar(ConsulServiceRegistry consulServiceRegistry) {
        this.consulServiceRegistry = consulServiceRegistry;
    }

    @EventListener
    public void onGrpcServerStarted(GRpcServerInitializedEvent event) {

        ApplicationContext applicationContext = event.getApplicationContext();

        final GrpcConsulProperties gRpcConsulProperties = applicationContext
                .getBean(GrpcConsulProperties.class);



        registrations = gRpcConsulProperties
                .getRegistrationMode()
                .createServices(event.getServer(),applicationContext)
                .stream()
                .map(s->new ConsulRegistration(s, gRpcConsulProperties.getDiscovery()))
                .collect(Collectors.toList());

        registrations.forEach(consulServiceRegistry::register);
    }




    @Override
    public boolean isAutoStartup() {
        return false;
    }

    @Override
    public void stop(Runnable callback) {
        stop();
        callback.run();
    }

    @Override
    public void start() {

    }

    @Override
    public synchronized void stop() {

        registrations.forEach(consulServiceRegistry::deregister);
        consulServiceRegistry.close();
        registrations = null;

    }

    @Override
    public synchronized boolean isRunning() {
        return null != registrations;
    }

    @Override
    public int getPhase() {
        return 0;
    }
}

package com.muratoksuzer.vp.entity.domain;

import jakarta.persistence.*;

import java.math.BigDecimal;

@Entity
@Table(name = "sale_line",
        indexes = @Index(name = "ix_sale_line_sale", columnList = "sale_id"))
public class SaleLine {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @ManyToOne(optional = false, fetch = FetchType.LAZY)
    private Sale sale;

    @ManyToOne(optional = false, fetch = FetchType.LAZY)
    private Product product;

    @Column(nullable = false, precision = 19, scale = 3)
    private BigDecimal quantity;

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal unitPrice;

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal lineTotal;

    public SaleLine() {
    }

    public SaleLine(Sale sale, Product product, BigDecimal quantity, BigDecimal unitPrice) {
        this.sale = sale;
        this.product = product;
        this.quantity = quantity;
        this.unitPrice = unitPrice;
        this.lineTotal = unitPrice.multiply(quantity);
    }

    public Long getId() {
        return id;
    }

    public Sale getSale() {
        return sale;
    }

    public void setSale(Sale sale) {
        this.sale = sale;
    }

    public Product getProduct() {
        return product;
    }

    public void setProduct(Product product) {
        this.product = product;
    }

    public BigDecimal getQuantity() {
        return quantity;
    }

    public void setQuantity(BigDecimal quantity) {
        this.quantity = quantity;
    }

    public BigDecimal getUnitPrice() {
        return unitPrice;
    }

    public void setUnitPrice(BigDecimal unitPrice) {
        this.unitPrice = unitPrice;
    }

    public BigDecimal getLineTotal() {
        return lineTotal;
    }

    public void setLineTotal(BigDecimal lineTotal) {
        this.lineTotal = lineTotal;
    }
}

package market.domain;

import javax.persistence.Column;
import javax.persistence.EmbeddedId;
import javax.persistence.Entity;
import javax.persistence.FetchType;
import javax.persistence.JoinColumn;
import javax.persistence.ManyToOne;
import javax.persistence.MapsId;
import javax.persistence.Table;
import java.io.Serializable;
import java.util.Objects;

@Entity
@Table(name = "cart_item")
public class CartItem implements Serializable {
	private static final long serialVersionUID = -3995571478236070123L;

	@EmbeddedId
	private CartItemId pk = new CartItemId();

	@MapsId("cartId")
	@JoinColumn(name = "cart_id", referencedColumnName = "id")
	@ManyToOne(optional = false, fetch = FetchType.LAZY)
	private Cart cart;

	@MapsId("productId")
	@JoinColumn(name = "product_id", referencedColumnName = "id")
	@ManyToOne(optional = false, fetch = FetchType.EAGER)
	private Product product;

	@Column(name = "quantity")
	private int quantity;

	public CartItem() {
	}

	public CartItem(Cart cart, Product product, int quantity) {
		this.pk = new CartItemId(cart.getId(), product.getId());
		this.cart = cart;
		this.product = product;
		this.quantity = quantity;
	}

	public double calculateCost() {
		return quantity * product.getPrice();
	}

	public int getQuantity() {
		return quantity;
	}

	public void setQuantity(int quantity) {
		this.quantity = quantity;
	}

	public Product getProduct() {
		return product;
	}

	public void setProduct(Product product) {
		this.product = product;
		pk.setProduct(product.getId());
	}

	@Override
	public boolean equals(Object o) {
		if (this == o) {
			return true;
		}
		if (o == null || getClass() != o.getClass()) {
			return false;
		}
		CartItem that = (CartItem) o;
		return Objects.equals(pk, that.pk);
	}

	@Override
	public int hashCode() {
		return (pk != null ? pk.hashCode() : 0);
	}
}

package edu.sabanciuniv.hotelbookingapp.model;

import jakarta.persistence.*;
import lombok.*;
import org.hibernate.annotations.CreationTimestamp;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;
import java.util.UUID;

@Entity
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class Booking {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(unique = true, nullable = false)
    private String confirmationNumber;

    @CreationTimestamp
    private LocalDateTime bookingDate;

    @ManyToOne
    @JoinColumn(nullable = false)
    private Customer customer;

    @ManyToOne
    @JoinColumn(nullable = true)
    private Hotel hotel;

    @Column(nullable = false)
    private LocalDate checkinDate;

    @Column(nullable = false)
    private LocalDate checkoutDate;

    @OneToMany(mappedBy = "booking", cascade = CascadeType.ALL, orphanRemoval = true)
    @Builder.Default
    private List<BookedRoom> bookedRooms = new ArrayList<>();

    @OneToOne(mappedBy = "booking")
    private Payment payment;

    @PrePersist
    protected void onCreate() {
        this.confirmationNumber = UUID.randomUUID().toString().substring(0, 8);
    }

    @Override
    public String toString() {
        return "Booking{" +
                "id=" + id +
                ", confirmationNumber='" + confirmationNumber + '\'' +
                ", bookingDate=" + bookingDate +
                ", customer=" + customer +
                ", hotel=" + hotel +
                ", checkinDate=" + checkinDate +
                ", checkoutDate=" + checkoutDate +
                ", bookedRooms=" + bookedRooms +
                ", payment=" + payment +
                '}';
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Booking booking = (Booking) o;
        return Objects.equals(id, booking.id) && Objects.equals(confirmationNumber, booking.confirmationNumber);
    }

    @Override
    public int hashCode() {
        return Objects.hash(id, confirmationNumber);
    }
}

